unc_mack_tbl <- unc_tbl |>
  dplyr::filter(coach %in% c("Mack Brown 1.0 60% | 69-46", 
  "Mack Brown 2.0 56.9% | 41-31")) |>
  dplyr::arrange(season) |> 
  gt::gt(groupname_col = "coach") |>
  gtUtils::gt_indicator_boxes(
    key_columns = "season",
    color_yes = "#56a0d3",
    color_no = "#e75480",
    color_na = "#e1e1e1"
  ) |>
  gt::cols_label(season = "") |>
  gtUtils::gt_theme_sofa() |>
  gt::tab_spanner(columns = c(-season), label = "Game Number") |>
